// // This is a 16-to-4 decoder that takes a 4-bit binary input and activates one of the 4 output lines based on the input value.
module decoder_4_to_16 (
    input [3:0] in,
    output reg [15:0] out
);
    always @(*) begin
        out = 16'b0; // Initialize all outputs to 0
        out[in] = 1'b1; // Set the output corresponding to the input
    end
endmodule
